// // This module implements a 2-to-4 decoder with a 16-bit output. The output is controlled by the 2-bit selection input `sel`, and the enable input `en` determines whether the selected bit is set to 0 or remains high.
module top_module(
    input [1:0] sel,
    input en,
    output reg [15:0] out
);always @ (sel, en) begin
    case (sel)
        2'b00: out = en ? 16'b1111111111111110 : 16'b1111111111111111;
        2'b01: out = en ? 16'b1111111111111101 : 16'b1111111111111111;
        2'b10: out = en ? 16'b1111111111111011 : 16'b1111111111111111;
        2'b11: out = en ? 16'b1111111111110111 : 16'b1111111111111111;
        default: out = 16'b1111111111111111;
    endcase
end

endmodule
